(window.webpackJsonp=window.webpackJsonp||[]).push([[1345],{1614:function(s){s.exports=JSON.parse('{"code":["<pre class=\\"hljs\\"><code><span class=\\"hljs-comment\\">/**\\n * Definition for a binary tree node.\\n * function TreeNode(val) {\\n *     this.val = val;\\n *     this.left = this.right = null;\\n * }\\n */</span>\\n<span class=\\"hljs-comment\\">/**\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{TreeNode}</span> <span class=\\"hljs-variable\\">root</span></span>\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{number[]}</span> <span class=\\"hljs-variable\\">voyage</span></span>\\n * <span class=\\"hljs-doctag\\">@return <span class=\\"hljs-type\\">{number[]}</span></span>\\n */</span>\\n<span class=\\"hljs-keyword\\">var</span> flipMatchVoyage = <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span>(<span class=\\"hljs-params\\">root, voyage</span>) </span>{\\n  <span class=\\"hljs-keyword\\">let</span> res=[],idx=<span class=\\"hljs-number\\">0</span>\\n  <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span> <span class=\\"hljs-title\\">dfs</span>(<span class=\\"hljs-params\\">root</span>)</span>{\\n    <span class=\\"hljs-keyword\\">if</span>(!root)<span class=\\"hljs-keyword\\">return</span> <span class=\\"hljs-literal\\">true</span>\\n    <span class=\\"hljs-comment\\">// console.log(idx,root.val)</span>\\n    <span class=\\"hljs-keyword\\">if</span>(root.val !== voyage[idx++])<span class=\\"hljs-keyword\\">return</span> <span class=\\"hljs-literal\\">false</span>\\n    <span class=\\"hljs-keyword\\">let</span> n=idx\\n    <span class=\\"hljs-keyword\\">if</span>(!dfs(root.left) || !dfs(root.right)){\\n      idx=n\\n      res.push(root.val)\\n      <span class=\\"hljs-comment\\">// console.log(res,root.val)</span>\\n      <span class=\\"hljs-keyword\\">return</span> dfs(root.right) &amp;&amp; dfs(root.left)\\n    }<span class=\\"hljs-keyword\\">else</span>{\\n      <span class=\\"hljs-keyword\\">return</span> <span class=\\"hljs-literal\\">true</span>\\n    }\\n  }\\n  <span class=\\"hljs-keyword\\">let</span> r=dfs(root)\\n  <span class=\\"hljs-comment\\">// console.log(idx)</span>\\n  <span class=\\"hljs-keyword\\">if</span>(!r || idx!==voyage.length)<span class=\\"hljs-keyword\\">return</span> [<span class=\\"hljs-number\\">-1</span>]\\n  <span class=\\"hljs-keyword\\">return</span> res\\n  \\n};\\n</code></pre>\\n"],"titleSlug":"flip-binary-tree-to-match-preorder-traversal","hasThinking":false,"content":"<p>\u7ed9\u4f60\u4e00\u68f5\u4e8c\u53c9\u6811\u7684\u6839\u8282\u70b9 <code>root</code> \uff0c\u6811\u4e2d\u6709 <code>n</code> \u4e2a\u8282\u70b9\uff0c\u6bcf\u4e2a\u8282\u70b9\u90fd\u6709\u4e00\u4e2a\u4e0d\u540c\u4e8e\u5176\u4ed6\u8282\u70b9\u4e14\u5904\u4e8e <code>1</code> \u5230 <code>n</code> \u4e4b\u95f4\u7684\u503c\u3002</p>\\n\\n<p>\u53e6\u7ed9\u4f60\u4e00\u4e2a\u7531 <code>n</code> \u4e2a\u503c\u7ec4\u6210\u7684\u884c\u7a0b\u5e8f\u5217 <code>voyage</code> \uff0c\u8868\u793a <strong>\u9884\u671f</strong> \u7684\u4e8c\u53c9\u6811 <a href=\\"https://baike.baidu.com/item/%E5%85%88%E5%BA%8F%E9%81%8D%E5%8E%86/6442839?fr=aladdin\\" target=\\"_blank\\"><strong>\u5148\u5e8f\u904d\u5386</strong></a> \u7ed3\u679c\u3002</p>\\n\\n<p>\u901a\u8fc7\u4ea4\u6362\u8282\u70b9\u7684\u5de6\u53f3\u5b50\u6811\uff0c\u53ef\u4ee5 <strong>\u7ffb\u8f6c</strong> \u8be5\u4e8c\u53c9\u6811\u4e2d\u7684\u4efb\u610f\u8282\u70b9\u3002\u4f8b\uff0c\u7ffb\u8f6c\u8282\u70b9 1 \u7684\u6548\u679c\u5982\u4e0b\uff1a</p>\\n<img alt=\\"\\" src=\\"https://assets.leetcode.com/uploads/2021/02/15/fliptree.jpg\\" style=\\"width: 400px; height: 187px;\\" />\\n<p>\u8bf7\u7ffb\u8f6c <strong>\u6700\u5c11 </strong>\u7684\u6811\u4e2d\u8282\u70b9\uff0c\u4f7f\u4e8c\u53c9\u6811\u7684 <strong>\u5148\u5e8f\u904d\u5386</strong> \u4e0e\u9884\u671f\u7684\u904d\u5386\u884c\u7a0b\xa0<code>voyage</code>\xa0<strong>\u76f8\u5339\u914d</strong> \u3002\xa0</p>\\n\\n<p>\u5982\u679c\u53ef\u4ee5\uff0c\u5219\u8fd4\u56de <strong>\u7ffb\u8f6c\u7684</strong> \u6240\u6709\u8282\u70b9\u7684\u503c\u7684\u5217\u8868\u3002\u4f60\u53ef\u4ee5\u6309\u4efb\u4f55\u987a\u5e8f\u8fd4\u56de\u7b54\u6848\u3002\u5982\u679c\u4e0d\u80fd\uff0c\u5219\u8fd4\u56de\u5217\u8868 <code>[-1]</code>\u3002</p>\\n\\n<p>\xa0</p>\\n\\n<p><strong>\u793a\u4f8b 1\uff1a</strong></p>\\n<img alt=\\"\\" src=\\"https://assets.leetcode.com/uploads/2019/01/02/1219-01.png\\" style=\\"width: 150px; height: 205px;\\" />\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>root = [1,2], voyage = [2,1]\\n<strong>\u8f93\u51fa\uff1a</strong>[-1]\\n<strong>\u89e3\u91ca\uff1a</strong>\u7ffb\u8f6c\u8282\u70b9\u65e0\u6cd5\u4ee4\u5148\u5e8f\u904d\u5386\u5339\u914d\u9884\u671f\u884c\u7a0b\u3002\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 2\uff1a</strong></p>\\n<img alt=\\"\\" src=\\"https://assets.leetcode.com/uploads/2019/01/02/1219-02.png\\" style=\\"width: 150px; height: 142px;\\" />\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>root = [1,2,3], voyage = [1,3,2]\\n<strong>\u8f93\u51fa\uff1a</strong>[1]\\n<strong>\u89e3\u91ca\uff1a</strong>\u4ea4\u6362\u8282\u70b9 2 \u548c 3 \u6765\u7ffb\u8f6c\u8282\u70b9 1 \uff0c\u5148\u5e8f\u904d\u5386\u53ef\u4ee5\u5339\u914d\u9884\u671f\u884c\u7a0b\u3002</pre>\\n\\n<p><strong>\u793a\u4f8b 3\uff1a</strong></p>\\n<img alt=\\"\\" src=\\"https://assets.leetcode.com/uploads/2019/01/02/1219-02.png\\" style=\\"width: 150px; height: 142px;\\" />\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>root = [1,2,3], voyage = [1,2,3]\\n<strong>\u8f93\u51fa\uff1a</strong>[]\\n<strong>\u89e3\u91ca\uff1a</strong>\u5148\u5e8f\u904d\u5386\u5df2\u7ecf\u5339\u914d\u9884\u671f\u884c\u7a0b\uff0c\u6240\u4ee5\u4e0d\u9700\u8981\u7ffb\u8f6c\u8282\u70b9\u3002\\n</pre>\\n\\n<p>\xa0</p>\\n\\n<p><strong>\u63d0\u793a\uff1a</strong></p>\\n\\n<ul>\\n\\t<li>\u6811\u4e2d\u7684\u8282\u70b9\u6570\u76ee\u4e3a <code>n</code></li>\\n\\t<li><code>n == voyage.length</code></li>\\n\\t<li><code>1 <= n <= 100</code></li>\\n\\t<li><code>1 <= Node.val, voyage[i] <= n</code></li>\\n\\t<li>\u6811\u4e2d\u7684\u6240\u6709\u503c <strong>\u4e92\u4e0d\u76f8\u540c</strong></li>\\n\\t<li><code>voyage</code> \u4e2d\u7684\u6240\u6709\u503c <strong>\u4e92\u4e0d\u76f8\u540c</strong></li>\\n</ul>\\n","title":"971. \u7ffb\u8f6c\u4e8c\u53c9\u6811\u4ee5\u5339\u914d\u5148\u5e8f\u904d\u5386","relatedTags":["\u6811","\u6df1\u5ea6\u4f18\u5148\u641c\u7d22"],"difficult":"Middle","lang":["javascript"],"uniqueID":"971"}')}}]);